package com.enterprise.app.repository;

import com.enterprise.app.entity.Account;
import com.enterprise.app.entity.AccountStatus;
import com.enterprise.app.entity.AccountType;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Lock;
import org.springframework.data.jpa.repository.Modifying;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;
import org.springframework.stereotype.Repository;

import jakarta.persistence.LockModeType;
import java.math.BigDecimal;
import java.util.List;
import java.util.Optional;

@Repository
public interface AccountRepository extends JpaRepository<Account, Long> {

    Optional<Account> findByAccountNumber(String accountNumber);

    @Lock(LockModeType.PESSIMISTIC_WRITE)
    @Query("SELECT a FROM Account a WHERE a.accountNumber = :accountNumber")
    Optional<Account> findByAccountNumberForUpdate(@Param("accountNumber") String accountNumber);

    @Lock(LockModeType.PESSIMISTIC_WRITE)
    @Query("SELECT a FROM Account a WHERE a.id = :id")
    Optional<Account> findByIdForUpdate(@Param("id") Long id);

    List<Account> findByUserId(Long userId);

    Page<Account> findByUserId(Long userId, Pageable pageable);

    List<Account> findByUserIdAndStatus(Long userId, AccountStatus status);

    List<Account> findByAccountType(AccountType accountType);

    @Query("SELECT a FROM Account a WHERE a.balance < :threshold AND a.status = 'ACTIVE'")
    List<Account> findLowBalanceAccounts(@Param("threshold") BigDecimal threshold);

    @Modifying
    @Query("UPDATE Account a SET a.status = :status WHERE a.id = :accountId")
    int updateAccountStatus(@Param("accountId") Long accountId, @Param("status") AccountStatus status);

    @Query("SELECT SUM(a.balance) FROM Account a WHERE a.user.id = :userId AND a.status = 'ACTIVE'")
    BigDecimal getTotalBalanceByUserId(@Param("userId") Long userId);

    @Query("SELECT COUNT(a) FROM Account a WHERE a.user.id = :userId AND a.status = :status")
    long countByUserIdAndStatus(@Param("userId") Long userId, @Param("status") AccountStatus status);

    boolean existsByAccountNumber(String accountNumber);
}

