package com.enterprise.app.repository;

import com.enterprise.app.entity.Transaction;
import com.enterprise.app.entity.TransactionStatus;
import com.enterprise.app.entity.TransactionType;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;
import org.springframework.stereotype.Repository;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;
import java.util.Optional;

@Repository
public interface TransactionRepository extends JpaRepository<Transaction, Long> {

    Optional<Transaction> findByReferenceNumber(String referenceNumber);

    Page<Transaction> findByUserId(Long userId, Pageable pageable);

    List<Transaction> findByUserIdAndStatus(Long userId, TransactionStatus status);

    Page<Transaction> findBySourceAccountId(Long accountId, Pageable pageable);

    Page<Transaction> findByDestinationAccountId(Long accountId, Pageable pageable);

    @Query("SELECT t FROM Transaction t WHERE t.sourceAccount.id = :accountId OR t.destinationAccount.id = :accountId ORDER BY t.transactionDate DESC")
    Page<Transaction> findAllByAccountId(@Param("accountId") Long accountId, Pageable pageable);

    @Query("SELECT t FROM Transaction t WHERE t.user.id = :userId AND t.transactionDate BETWEEN :startDate AND :endDate")
    List<Transaction> findByUserIdAndDateRange(@Param("userId") Long userId,
                                                @Param("startDate") LocalDateTime startDate,
                                                @Param("endDate") LocalDateTime endDate);

    @Query("SELECT t FROM Transaction t WHERE t.user.id = :userId AND t.transactionType = :type AND t.transactionDate BETWEEN :startDate AND :endDate")
    Page<Transaction> findByUserIdAndTypeAndDateRange(@Param("userId") Long userId,
                                                       @Param("type") TransactionType type,
                                                       @Param("startDate") LocalDateTime startDate,
                                                       @Param("endDate") LocalDateTime endDate,
                                                       Pageable pageable);

    @Query("SELECT SUM(t.amount) FROM Transaction t WHERE t.user.id = :userId AND t.transactionType = :type AND t.status = 'COMPLETED' AND t.transactionDate BETWEEN :startDate AND :endDate")
    BigDecimal sumAmountByUserAndTypeAndDateRange(@Param("userId") Long userId,
                                                   @Param("type") TransactionType type,
                                                   @Param("startDate") LocalDateTime startDate,
                                                   @Param("endDate") LocalDateTime endDate);

    @Query("SELECT COUNT(t) FROM Transaction t WHERE t.user.id = :userId AND t.status = :status")
    long countByUserIdAndStatus(@Param("userId") Long userId, @Param("status") TransactionStatus status);

    List<Transaction> findByStatusAndCreatedAtBefore(TransactionStatus status, LocalDateTime date);

    @Query("SELECT t FROM Transaction t WHERE t.amount > :amount AND t.status = 'COMPLETED' ORDER BY t.amount DESC")
    List<Transaction> findHighValueTransactions(@Param("amount") BigDecimal amount);

    @Query(value = "SELECT DATE(t.transaction_date) as txn_date, COUNT(*) as txn_count, SUM(t.amount) as total_amount " +
            "FROM transactions t WHERE t.user_id = :userId AND t.status = 'COMPLETED' " +
            "AND t.transaction_date BETWEEN :startDate AND :endDate " +
            "GROUP BY DATE(t.transaction_date) ORDER BY txn_date", nativeQuery = true)
    List<Object[]> getDailyTransactionSummary(@Param("userId") Long userId,
                                               @Param("startDate") LocalDateTime startDate,
                                               @Param("endDate") LocalDateTime endDate);
}

